import{_ as e,o as t,c as r,a3 as o}from"./chunks/framework.BTFg6ESq.js";const g=JSON.parse('{"title":"💬 消息操作概览","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/llm-chat/messages/index.md","filePath":"user-guide/tools/llm-chat/messages/index.md","lastUpdated":1778239080000}'),l={name:"user-guide/tools/llm-chat/messages/index.md"};function s(i,a,n,h,d,c){return t(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="💬-消息操作概览" tabindex="-1">💬 消息操作概览 <a class="header-anchor" href="#💬-消息操作概览" aria-label="Permalink to &quot;💬 消息操作概览&quot;">​</a></h1><p>LLM Chat 的消息系统基于<strong>树状分支结构</strong>——每条消息都可以产生多个回复，形成一棵对话树。这让你可以自由探索不同的对话方向，而不会丢失已有的内容。</p><h2 id="核心交互" tabindex="-1">核心交互 <a class="header-anchor" href="#核心交互" aria-label="Permalink to &quot;核心交互&quot;">​</a></h2><h3 id="发送消息" tabindex="-1">发送消息 <a class="header-anchor" href="#发送消息" aria-label="Permalink to &quot;发送消息&quot;">​</a></h3><ul><li><strong>快捷键</strong>: 默认使用 <code>Ctrl + Enter</code> 发送，<code>Enter</code> 换行。</li><li><strong>分支逻辑</strong>: 如果你当前正在查看的历史节点已经有了后续回复，发送新消息会自动开启一个<strong>新的平行分支</strong>。</li></ul><h3 id="输入工具栏" tabindex="-1">输入工具栏 <a class="header-anchor" href="#输入工具栏" aria-label="Permalink to &quot;输入工具栏&quot;">​</a></h3><p>输入框上方集成了多种增强工具：</p><ul><li>📎 <strong>附件管理</strong>: 添加图片、文档或音频。</li><li>🤖 <strong>快速切换</strong>: 实时更换当前使用的 Agent。</li><li>⚡ <strong>快捷动作</strong>: 触发预设的模板指令。</li><li>🔍 <strong>上下文预览</strong>: 在发送前检查即将提交给 LLM 的完整 Prompt。</li></ul><h2 id="消息树与分支" tabindex="-1">消息树与分支 <a class="header-anchor" href="#消息树与分支" aria-label="Permalink to &quot;消息树与分支&quot;">​</a></h2><p>分支是本系统的灵魂。你可以从任意历史节点“嫁接”出新的对话路径：</p><ul><li><strong>分支选择器</strong>: 消息卡片上下方的标签页，用于在平行分支间快速跳转。</li><li><strong>导航控制</strong>: 使用消息导航器 (Navigator) 在父子节点间前进或后退。</li><li><strong>全局视野</strong>: 切换到 <a href="./../sessions/tree-graph">对话树图</a> 视图，以可视化方式管理复杂的对话拓扑。</li></ul><h2 id="撤销与重做-snapshot" tabindex="-1">撤销与重做 (Snapshot) <a class="header-anchor" href="#撤销与重做-snapshot" aria-label="Permalink to &quot;撤销与重做 (Snapshot)&quot;">​</a></h2><p>系统为每个会话维护了全量快照历史：</p><ul><li>使用 <code>Ctrl + Z</code> 撤销上一次的消息编辑、删除或分支切换。</li><li>撤销操作不仅恢复文本，还会恢复整个消息树的物理结构。</li></ul><hr><h3 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h3><ul><li><a href="./message-list">消息列表与悬浮操作栏</a></li><li><a href="./message-data-editor">消息数据编辑器 (高级)</a></li><li><a href="./path-to-attachment">文件路径转附件</a></li><li><a href="./continue-completion">续写与补全功能</a></li></ul>',17)])])}const p=e(l,[["render",s]]);export{g as __pageData,p as default};
